css:
.ept-form { font-family: "Times New Roman", Times, serif; font-size: 11pt; color: #000; }
.ept-title { text-align: center; font-size: 12pt; margin: 0 0 4px; }
.ept-subtitle { text-align: center; margin: 0 0 12px; }
.ept-meta { width: 100%; margin-bottom: 14px; border-collapse: collapse; }
.ept-meta td { padding: 3px 0; vertical-align: top; }
.reading-title { text-align: center; font-size: 11pt; margin: 12px 0 8px; text-transform: uppercase; }
.reading-passage { text-align: justify; margin-bottom: 16px; line-height: 1.35; }
.question-block { margin-bottom: 12px; page-break-inside: avoid; }
.question-text { margin: 0 0 4px; }
.options { margin-left: 16px; }
.option-row { margin: 2px 0; }
.box { display: inline-block; width: 14px; }
